  1→import React from 'react';
  2→import { useNavigate } from 'react-router-dom';
  3→import { useAuth } from '../../../Context/useAuth';
  4→import { useMyStories } from '../hooks/useStoryData';
  5→import { useDeleteStory } from '../hooks/useStoryMutations';
  6→import { motion, AnimatePresence } from 'framer-motion';
  7→import { BeatLoader } from 'react-spinners';
  8→import './StoryDashboard.css';
  9→
 10→const STATUS_LABELS = {
 11→    ongoing: 'Ongoing',
 12→    completed: 'Completed',
 13→    hiatus: 'Hiatus',
 14→};
 15→
 16→const StoryDashboard = () => {
 17→    const { session } = useAuth();
 18→    const token = session?.access_token;
 19→    const navigate = useNavigate();
 20→
 21→    const { data: stories, isLoading } = useMyStories(token);
 22→    const deleteMutation = useDeleteStory(token);
 23→
 24→    const handleDelete = (e, storyId, title) => {
 25→        e.stopPropagation();
 26→        if (window.confirm(`Delete "${title}"? This cannot be undone.`)) {
 27→            deleteMutation.mutate(storyId);
 28→        }
 29→    };
 30→
 31→    const getTotalWords = (chapters) => {
 32→        if (!chapters) return 0;
 33→        return chapters.reduce((sum, ch) => sum + (ch.word_count || 0), 0);
 34→    };
 35→
 36→    const getPublishedCount = (chapters) => {
 37→        if (!chapters) return 0;
 38→        return chapters.filter(ch => ch.status === 'published').length;
 39→    };
 40→
 41→    if (isLoading) {
 42→        return (
 43→            <div className="story-dashboard">
 44→                <div className="story-dashboard-loading">
 45→                    <BeatLoader size={10} color="var(--text-muted)" />
 46→                </div>
 47→            </div>
 48→        );
 49→    }
 50→
 51→    return (
 52→        <div className="story-dashboard">
 53→            <div className="story-dashboard-header">
 54→                <h2 className="story-dashboard-title">My Stories</h2>
 55→                <button
 56→                    className="story-dashboard-new-btn"
 57→                    onClick={() => navigate('/home/stories/new')}
 58→                >
 59→                    + New Story
 60→                </button>
 61→            </div>
 62→
 63→            {(!stories || stories.length === 0) ? (
 64→                <div className="story-dashboard-empty">
 65→                    <p>You haven't written any stories yet.</p>
 66→                    <button
 67→                        className="story-dashboard-new-btn"
 68→                        onClick={() => navigate('/home/stories/new')}
 69→                    >
 70→                        Write Your First Story
 71→                    </button>
 72→                </div>
 73→            ) : (
 74→                <div className="story-dashboard-list">
 75→                    <AnimatePresence>
 76→                        {stories.map((story) => (
 77→                            <motion.div
 78→                                key={story.id}
 79→                                className="story-dashboard-card"
 80→                                initial={{ opacity: 0, y: 10 }}
 81→                                animate={{ opacity: 1, y: 0 }}
 82→                                exit={{ opacity: 0, y: -10 }}
 83→                                onClick={() => navigate(`/home/stories/${story.id}/manage`)}
 84→                            >
 85→                                <div className="story-dashboard-card-cover">
 86→                                    {story.cover_url ? (
 87→                                        <img src={story.cover_url} alt={story.title} loading="lazy" />
 88→                                    ) : (
 89→                                        <div className="story-dashboard-card-cover-placeholder">
 90→                                            <svg xmlns="http://www.w3.org/2000/svg" width="32" height="32" viewBox="0 0 24 24" fill="var(--text-muted)">
 91→                                                <path d="M21 5c-1.11-.35-2.33-.5-3.5-.5-1.95 0-4.05.4-5.5 1.5-1.45-1.1-3.55-1.5-5.5-1.5S2.45 4.9 1 6v14.65c0 .25.25.5.5.5.1 0 .15-.05.25-.05C3.1 20.45 5.05 20 6.5 20c1.95 0 4.05.4 5.5 1.5 1.35-.85 3.8-1.5 5.5-1.5 1.65 0 3.35.3 4.75 1.05.1.05.15.05.25.05.25 0 .5-.25.5-.5V6c-.6-.45-1.25-.75-2-1zm0 13.5c-1.1-.35-2.3-.5-3.5-.5-1.7 0-4.15.65-5.5 1.5V8c1.35-.85 3.8-1.5 5.5-1.5 1.2 0 2.4.15 3.5.5v11.5z"/>
 92→                                            </svg>
 93→                                        </div>
 94→                                    )}
 95→                                </div>
 96→                                <div className="story-dashboard-card-info">
 97→                                    <h3 className="story-dashboard-card-title">{story.title}</h3>
 98→                                    <div className="story-dashboard-card-meta">
 99→                                        <span className={`story-status-badge story-status-${story.status}`}>
100→                                            {STATUS_LABELS[story.status] || story.status}
101→                                        </span>
102→                                        <span className="story-meta-dot">&middot;</span>
103→                                        <span>{getPublishedCount(story.chapters)}/{(story.chapters || []).length} chapters</span>
104→                                        <span className="story-meta-dot">&middot;</span>
105→                                        <span>{getTotalWords(story.chapters).toLocaleString()} words</span>
106→                                    </div>
107→                                    <div className="story-dashboard-card-stats">
108→                                        <span>{story.read_count || 0} reads</span>
109→                                        <span>{story.vote_count || 0} votes</span>
110→                                    </div>
111→                                </div>
112→                                <div className="story-dashboard-card-actions">
113→                                    <button
114→                                        className="story-action-btn"
115→                                        onClick={(e) => {
116→                                            e.stopPropagation();
117→                                            navigate(`/home/stories/${story.id}/edit`);
118→                                        }}
119→                                        title="Edit story details"
120→                                    >
121→                                        <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="var(--text-secondary)">
122→                                            <path d="M3 17.25V21h3.75L17.81 9.94l-3.75-3.75L3 17.25zM20.71 7.04c.39-.39.39-1.02 0-1.41l-2.34-2.34c-.39-.39-1.02-.39-1.41 0l-1.83 1.83 3.75 3.75 1.83-1.83z"/>
123→                                        </svg>
124→                                    </button>
125→                                    <button
126→                                        className="story-action-btn story-action-btn-danger"
127→                                        onClick={(e) => handleDelete(e, story.id, story.title)}
128→                                        title="Delete story"
129→                                    >
130→                                        <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="currentColor">
131→                                            <path d="M6 19c0 1.1.9 2 2 2h8c1.1 0 2-.9 2-2V7H6v12zM19 4h-3.5l-1-1h-5l-1 1H5v2h14V4z"/>
132→                                        </svg>
133→                                    </button>
134→                                </div>
135→                            </motion.div>
136→                        ))}
137→                    </AnimatePresence>
138→                </div>
139→            )}
140→        </div>
141→    );
142→};
143→
144→export default StoryDashboard;
