 17→
 18→    const { data: story, isLoading } = useStoryDetail(storyId, token);
 19→    const voteMutation = useToggleVote(token);
 20→    const libraryMutation = useToggleLibrary(token);
 21→
 22→    const handleVote = () => {
 23→        if (!session) return openAuthModal();
 24→        voteMutation.mutate(storyId);
